# app/vector_store/dual_write_store.py
import asyncio, logging
from app.vector_store.pinecone_store import PineconeStore
from app.vector_store.weaviate_store import WeaviateStore

log = logging.getLogger('dual_write_store')

class DualWriteVectorStore:
    def __init__(self, old: PineconeStore, new: WeaviateStore, read_from_new: bool = False):
        self.old = old
        self.new = new
        self.read_from_new = read_from_new  # controlled by feature flag

    async def upsert(self, id: str, vector: list[float], metadata: dict) -> None:
        await self.old.upsert(id, vector, metadata)  # primary, synchronous
        asyncio.ensure_future(self._upsert_new(id, vector, metadata))  # background

    async def _upsert_new(self, id: str, vector: list[float], metadata: dict) -> None:
        try:
            await self.new.upsert(id, vector, metadata)
        except Exception as exc:
            log.warning('New store write failed: %s -- old store remains authoritative', exc)

    async def query(self, vector: list[float], top_k: int) -> list[dict]:
        if self.read_from_new:
            return await self.new.query(vector, top_k)
        return await self.old.query(vector, top_k)

