import os

ACTIVE_EMBEDDING_MODEL = os.environ.get('ACTIVE_EMBEDDING_MODEL', 'ada-002')

MODEL_INDEX_MAP = {
    'ada-002':             'documents-ada-002',
    'text-embedding-3-lg': 'documents-te3-large',
}

def get_active_index() -> str:
    return MODEL_INDEX_MAP[ACTIVE_EMBEDDING_MODEL]

def get_query_embedding(text: str) -> list[float]:
    from openai import OpenAI
    model_id = {
        'ada-002': 'text-embedding-ada-002',
        'text-embedding-3-lg': 'text-embedding-3-large',
    }[ACTIVE_EMBEDDING_MODEL]
    resp = OpenAI().embeddings.create(model=model_id, input=text)
    return resp.data[0].embedding
